export default function r(n,o=n){const a=new Uint8ClampedArray(n*o*4);for(let t=0;t<a.length;)a[t++]=a[t++]=a[t++]=Math.random()*(a[t++]=255);const m=new ImageData(a,n),e=document.createElement("canvas");return e.width=n,e.height=o,e.getContext("2d").putImageData(m,0,0),e.remove(),e.toDataURL("image/png")}
